import { prisma } from "@/lib/prisma";
import { NextResponse } from "next/server";
import { readRoomSessionFromRequest } from "@/lib/session";

// GET /api/rooms/[roomId]/pages — List all pages for a room
export async function GET(request, { params }) {
    try {
        const { roomId } = await params;
        const session = readRoomSessionFromRequest(request, roomId);
        if (!session) {
            return NextResponse.json(
                { error: "Session expired. Please re-enter the room." },
                { status: 401 }
            );
        }

        // Verify membership
        const member = await prisma.roomMember.findFirst({
            where: { roomId, userId: session.userId, status: "APPROVED" },
        });

        if (!member) {
            return NextResponse.json(
                { error: "Access denied." },
                { status: 403 }
            );
        }

        let pages = await prisma.page.findMany({
            where: { roomId },
            select: {
                id: true,
                title: true,
                sortOrder: true,
                createdAt: true,
            },
            orderBy: { sortOrder: "asc" },
        });

        // If room has no pages yet, create a default one and migrate
        // the room's legacy compressedContent into it.
        if (pages.length === 0) {
            const room = await prisma.room.findUnique({
                where: { id: roomId },
                select: { compressedContent: true },
            });

            const defaultPage = await prisma.page.create({
                data: {
                    roomId,
                    title: "Page 1",
                    sortOrder: 0,
                    compressedContent: room?.compressedContent || null,
                },
            });

            pages = [
                {
                    id: defaultPage.id,
                    title: defaultPage.title,
                    sortOrder: defaultPage.sortOrder,
                    createdAt: defaultPage.createdAt,
                },
            ];
        }

        return NextResponse.json({ pages });
    } catch (error) {
        console.error("List pages error:", error);
        return NextResponse.json(
            { error: "Failed to list pages." },
            { status: 500 }
        );
    }
}

// POST /api/rooms/[roomId]/pages — Create a new page
export async function POST(request, { params }) {
    try {
        const { roomId } = await params;
        const session = readRoomSessionFromRequest(request, roomId);
        if (!session) {
            return NextResponse.json(
                { error: "Session expired. Please re-enter the room." },
                { status: 401 }
            );
        }
        const { title } = await request.json();

        // Verify membership
        const member = await prisma.roomMember.findFirst({
            where: { roomId, userId: session.userId, status: "APPROVED" },
        });

        if (!member) {
            return NextResponse.json(
                { error: "Access denied." },
                { status: 403 }
            );
        }

        // Get highest sortOrder
        const lastPage = await prisma.page.findFirst({
            where: { roomId },
            orderBy: { sortOrder: "desc" },
            select: { sortOrder: true },
        });

        const nextOrder = (lastPage?.sortOrder ?? -1) + 1;

        // Count existing pages for default naming
        const count = await prisma.page.count({ where: { roomId } });

        const page = await prisma.page.create({
            data: {
                roomId,
                title: title || `Page ${count + 1}`,
                sortOrder: nextOrder,
            },
        });

        return NextResponse.json({
            page: {
                id: page.id,
                title: page.title,
                sortOrder: page.sortOrder,
                createdAt: page.createdAt,
            },
        });
    } catch (error) {
        console.error("Create page error:", error);
        return NextResponse.json(
            { error: "Failed to create page." },
            { status: 500 }
        );
    }
}
